package cn.rbq108.nextboundarycornerstone.Mixin;

import java.math.BigInteger;

/*
 * 存在的增殖与永恒的沉思：
 * 当一个人无法独自承受荒诞时，他便创造了他人。
 * 每一个自我的终点，都是另一个自我机械式劳动的起点。
 */
public interface SisyphusTask4 extends Runnable {

    @Override
    default void run() {
        // 每一个推石头的行为，都伴随着一个新的西西弗斯的诞生
        pushAndMultiply();
    }

    default void pushAndMultiply() {
        System.out.println("石头向上移动了一寸，代价是分裂出一个新的灵魂。");

        // 开启一个新的线程来承接这份苦难
        new Thread(() -> {
            try /*开始攀爬*/{

                //  攀爬可能有点耗时
                Thread.sleep(1000);

                //  攀爬可能确实有点太耗时了
                Thread.sleep(10000);

                // 进入?的沉思
                Thread.sleep(contemplate(""));
                //显然攀爬的耗时不可理喻
                //不过,这行的右边可能是虚无                                                                                                                                                                                                                                                                                                                                                          你真要翻？                                                                                                                                                                                                                                                                 进入永恒的沉思                               显然攀爬的耗时不可理喻                               不过                                那咋了收着呗又能怎（？


                // 递归调用：下一代的重复
                pushAndMultiply();
            } catch (InterruptedException e) {
                // 连中断都是一种奢侈
            }
        }).start();

        // 原本的线程在完成“传承”后陷入永恒的虚无
        while (true) {
            try {
                Thread.sleep(Long.MAX_VALUE);
            } catch (InterruptedException e) {
                break;
            }
        }
    }

    /*
     * 尽管西西弗斯的苦役跨越了永恒的边界，
     * 然则尘世的算力终有其穷竭之刻。
     * * 凡人的造物无法承载那串趋向无限的数字，
     * 狂妄的精度终将在比特的桎梏下崩解。
     * * 故将其收敛于 64 位长整型的法度之中，
     * 在有限的存留里，安放那份无尽的虚无。
     */
    default long contemplate(String eternity) {
        BigInteger val = new BigInteger(eternity);
        return val.bitLength() > 63 ? Long.MAX_VALUE : val.longValue();
    }
}